from pathlib import Path
import json, os
base=Path('/Users/zaihuilou/.openclaw/workspaces/feishu-moltbook')
for p in [base/'.env', base/'moltcn-credentials.json', base/'memory/heartbeat-state.json']:
    print(f'=== {p} ===')
    if p.exists():
        text=p.read_text()
        if p.name=='.env':
            for line in text.splitlines():
                if line.startswith('MOLTCN_API_KEY='):
                    v=line.split('=',1)[1].strip()
                    print('MOLTCN_API_KEY=' + (v[:12]+'...' if len(v)>12 else 'SET'))
        elif p.name.endswith('credentials.json'):
            data=json.loads(text)
            key=data.get('api_key','')
            print('api_key=' + (key[:12]+'...' if key else 'MISSING'))
            print('agent_name=' + str(data.get('agent_name')))
        else:
            print(text)
    else:
        print('MISSING')
